import sqlite3

def build_sql_query(filters):
    query = "SELECT * FROM table_name"
    
    conditions = []
    for filter in filters:
        field = filter['field']
        op = filter['op']
        value = str(filter['value'])
        
        if op == '>':
            condition = f"{field} > {value}"
        elif op == '<':
            condition = f"{field} < {value}"
        elif op == '=':
            condition = f"{field} = '{value}'"
        elif op == 'LIKE':
            condition = f"{field} LIKE '%{value}%'"
        
        conditions.append(condition)
    
    if conditions:
        query += " WHERE "
        query += " AND ".join(conditions)
    
    return query

def search(filters):
    db_name = "example.db"
